import { useLoaderData, useNavigation, useRouteError } from 'react-router-dom';

export default function ProductPage() {
  const product = useLoaderData();
  const navigation = useNavigation();
  const error = useRouteError();

  if (navigation.state === 'loading') return <div>Chargement...</div>;
  if (error) return <div>Erreur : {error.statusText || 'Produit introuvable'}</div>;

  return (
    <div>
      <h1>{product.name}</h1>
      <p>Prix : {product.price} FCFA</p>
    </div>
  );
}
